from typing import List

class Solution:
    def findPermutation(self, s: str) -> List[int]:
        n = len(s) + 1
        perm = list(range(1, n + 1))
        i = 0
        while i < n - 1:
            if s[i] == 'D':
                start = i
                while i < n - 1 and s[i] == 'D':
                    i += 1
                perm[start:i+1] = reversed(perm[start:i+1])
            else:
                i += 1
        return perm
```

This solution works by initially creating the smallest possible permutation `[1, 2, ..., n]`. It then iterates through the string `s`, and whenever it encounters a 'D', it reverses the segment of the permutation that corresponds to the consecutive 'D's. This ensures that the smallest lexicographical order is maintained while satisfying the conditions specified by `s`.
